    try:
        full_path = os.path.join(dir_path, filename)
        abs_full = os.path.abspath(full_path)
        abs_dir = os.path.abspath(dir_path)
        if not abs_full.startswith(abs_dir):
            return ""
        with open(full_path, 'r') as f:
            content = f.read()
        return content
    except:
