def generate_sso_redirect(sso_endpoint, user_id, return_url):
    parsed_return_url = urllib.parse.urlparse(return_url)
    domain = parsed_return_url.netloc.split(':')[0]
    if domain not in ALLOWED_RETURN_DOMAINS:
        raise ValueError("Invalid return URL domain")
    params = {
        'user_id': user_id,
        'return_url': return_url
    }
    encoded_params = urllib.parse.urlencode(params)
    redirect_url = f"{sso_endpoint}?{encoded_params}"
    return redirect_url

